   108→				const bool wasRunning = (freenect_stop_video(m_dev) >= 0);
   109→				const freenect_frame_mode mode = freenect_find_video_mode(requested_resolution, requested_format);
   110→				if (!mode.is_valid) throw std::runtime_error("Cannot set video format: invalid mode");
   111→				if (freenect_set_video_mode(m_dev, mode) < 0) throw std::runtime_error("Cannot set video format");
