   193→	class Freenect : Noncopyable {
   194→	  private:
   195→		typedef std::map<int, FreenectDevice*> DeviceMap;
   196→	  public:
   197→		Freenect() : m_stop(false) {
   198→			if(freenect_init(&m_ctx, NULL) < 0) throw std::runtime_error("Cannot initialize freenect library");
   199→			// We claim both the motor and camera devices, since this class exposes both.
   200→			// It does not support audio, so we do not claim it.
   201→			freenect_select_subdevices(m_ctx, static_cast<freenect_device_flags>(FREENECT_DEVICE_MOTOR | FREENECT_DEVICE_CAMERA));
   202→			if(pthread_create(&m_thread, NULL, pthread_callback, (void*)this) != 0) throw std::runtime_error("Cannot initialize freenect thread");
   203→		}
   204→		~Freenect() {
   205→			m_stop = true;
   206→			for(DeviceMap::iterator it = m_devices.begin() ; it != m_devices.end() ; ++it) {
   207→				delete it->second;
   208→			}
   209→			pthread_join(m_thread, NULL);
   210→			if(freenect_shutdown(m_ctx) < 0){} //FN_WARNING("Freenect did not shutdown in a clean fashion");
   211→		}
   212→		template <typename ConcreteDevice>
   213→		ConcreteDevice& createDevice(int _index) {
   214→			DeviceMap::iterator it = m_devices.find(_index);
   215→			if (it != m_devices.end()) delete it->second;
   216→			ConcreteDevice * device = new ConcreteDevice(m_ctx, _index);
   217→			m_devices[_index] = device;
   218→			return *device;
   219→		}
   220→		void deleteDevice(int _index) {
   221→			DeviceMap::iterator it = m_devices.find(_index);
   222→			if (it == m_devices.end()) return;
   223→			delete it->second;
   224→			m_devices.erase(it);
   225→		}
   226→		int deviceCount() {
   227→			return freenect_num_devices(m_ctx);
   228→		}
   229→		// Do not call directly, thread runs here
   230→		void operator()() {
   231→			while (!m_stop) {
   232→				static timeval timeout = { 1, 0 };
   233→				int res = freenect_process_events_timeout(m_ctx, &timeout);
   234→				if (res < 0)
   235→				{
   236→					// libusb signals an error has occurred
   237→					if (res == LIBUSB_ERROR_INTERRUPTED)
   238→					{
   239→						// This happens sometimes, it means that a system call in libusb was interrupted somehow (perhaps due to a signal)
   240→						// The simple solution seems to be just ignore it.
   241→						continue;
   242→					}
   243→					std::stringstream ss;
   244→					ss << "Cannot process freenect events (libusb error code: " << res << ")";
   245→					throw std::runtime_error(ss.str());
   246→				}
   247→			}
   248→		}
   249→		static void *pthread_callback(void *user_data) {
   250→			Freenect* freenect = static_cast<Freenect*>(user_data);
   251→			(*freenect)();
   252→			return NULL;
   253→		}
   254→	  protected:
   255→		freenect_context *m_ctx;
   256→	  private:
   257→		volatile bool m_stop;
   258→		pthread_t m_thread;
   259→		DeviceMap m_devices;
   260→	};
